// LoadMember loads the taskComment's Member into the .R struct
func (o *TaskComment) LoadMember(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Member = nil

	related, err := o.Member(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.TaskComments = TaskCommentSlice{o}

	o.R.Member = related
	return nil
}

// LoadMember loads the taskComment's Member into the .R struct
func (os TaskCommentSlice) LoadMember(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	members, err := os.Member(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range members {

			if !(o.WorkspaceID == rel.WorkspaceID) {
				continue
			}

			if !(o.AuthorID == rel.ID) {
				continue
			}

			rel.R.TaskComments = append(rel.R.TaskComments, o)

			o.R.Member = rel
			break
		}
	}

	return nil
}

