type taskCommentJoins[Q dialect.Joinable] struct {
	typ       string
	Member    modAs[Q, memberColumns]
	Workspace modAs[Q, workspaceColumns]
	Task      modAs[Q, taskColumns]
}

func (j taskCommentJoins[Q]) aliasedAs(alias string) taskCommentJoins[Q] {
	return buildTaskCommentJoins[Q](buildTaskCommentColumns(alias), j.typ)
}

func buildTaskCommentJoins[Q dialect.Joinable](cols taskCommentColumns, typ string) taskCommentJoins[Q] {
	return taskCommentJoins[Q]{
		typ: typ,
		Member: modAs[Q, memberColumns]{
			c: Members.Columns,
			f: func(to memberColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Members.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.WorkspaceID), to.ID.EQ(cols.AuthorID),
					))
				}

				return mods
			},
		},
		Workspace: modAs[Q, workspaceColumns]{
			c: Workspaces.Columns,
			f: func(to workspaceColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Workspaces.Name().As(to.Alias())).On(
						to.ID.EQ(cols.WorkspaceID),
					))
				}

				return mods
			},
		},
		Task: modAs[Q, taskColumns]{
			c: Tasks.Columns,
			f: func(to taskColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Tasks.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.WorkspaceID), to.ID.EQ(cols.TaskID),
					))
				}

				return mods
			},
		},
	}
}
